import React, { useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton, } from "@coreui/react";
import FormInput from '../../utils/FormInput';
import GoBackComponent from 'src/utils/GoBackComponent';
import { createProduct, getProductById, updateProduct } from 'src/components/services/ProductApi';
import TextArea from 'src/utils/TextArea';
import authService from 'src/auth/auth.service';


const ProductForm = (props) => {

    const navigate = useNavigate();
    const { type,id } = props;
    const [errors, setErrors] = useState({});
    const [inputFieldValue, setInputFieldValue] = useState({ productName: '', description:  ''});
    const [errorMessage, setErrorMessage] = useState("");

    useEffect(() => {
        if(type === "UPDATE"){
            fetchProductDetailsById(id);
        }

    },[])

    const handleChange = (event) => {
        setInputFieldValue((inputField) => ({ ...inputField, [event.target.name]: event.target.name === "productName"  ? event.target.value.trimStart()?.replace(/[^a-zA-Z ]/g, "") : event.target.value.trimStart() }));
    }

    const fetchProductDetailsById = async() => {
        let response =  await getProductById(id) 
            if(response?.message === "Success!") {
                let productDetails = response?.body;
                setInputFieldValue((prevInputField) => ({...prevInputField, productName: response?.body?.name, description: response?.body?.description}));
            }
    }

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        if (!inputFieldValue?.productName) {
            errors['productName'] = "Please enter product name";
            formIsValid = false;
        }
        if(!inputFieldValue?.description) {
            errors['description'] = "Please enter description";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                name: inputFieldValue?.productName,
                description: inputFieldValue?.description,
                ...(id && { id: id })
            }

            let response = {};
            if(type === "CREATE"){
                response = await createProduct(postData) 
            }else{
                response = await updateProduct(postData)
            }
            if(response?.status === "201 CREATED" || response?.status === "202 ACCEPTED") {
                navigate("/product");
            }
            if(response?.status === "409 CONFLICT") {
                setErrorMessage(response?.message);
            }
            setTimeout(() => {
                setErrorMessage("");
            }, 3000)
        }
    };

    return (
        <>
            <GoBackComponent goBackData={"product"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={8}>
                        <FormInput
                            value={inputFieldValue?.productName}
                            label={"Product Name"}
                            name={"productName"}
                            onChange={handleChange}
                            required={true}
                            error={errors['productName']}
                        />
                    </CCol>

                    <CCol md={12}>
                        <TextArea
                        value={inputFieldValue?.description}
                        label={"Description"}
                        name={"description"}
                        onChange={handleChange}
                        required={true}
                        error={errors['description']}
                        />
                    </CCol>
                    {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                   {authService.getPermission(type === "CREATE" ? "PRODUCT_CREATE" : "PRODUCT_UPDATE") && 
                        <CCol md={12}>
                            <CButton color="primary" onClick={handleSubmit} className="d-block">
                                {type === "CREATE" ? "Create" : "Update"}
                            </CButton>
                        </CCol>}
                </CForm>
            </div>
        </>
    );
}

export default ProductForm;
